local LxNodeBase = require("LApp.component.LxNodeBase")
---@class BuildingAdCard:LxNodeBase
local BuildingAdCard = LxClass("BuildingAdCard", LxNodeBase)

-----------------------------------------------------------------
local typeSpriteRenderer = typeof(UnityEngine.SpriteRenderer)
local Tweening = DG.Tweening
-----------------------------------------------------------------
function BuildingAdCard:BuildingAdCard()
	self._bLoginShow = true
    self._cityMap = nil
	self._rootTrans = nil
	self._slotUseList = {}
	self._slotIndex = 0
	self._curIconIndex = 0
	
	-- 1:功能预告 2:玩法预告 
	self._adCardType = 0
	self._adCardList = {}
	
	self._autoChangetimer = nil
	self._autoChangeFunc = nil
	self._autoChangeSpaceTime = 5
end

function BuildingAdCard:Destroy()
	if self._autoChangetimer then
		LxTimer.LoopTimeStop(self._autoChangetimer)
		self._autoChangetimer = nil
	end
	if self._adEffect then
		self._adEffect:Destroy()
		self._adEffect = nil
	end
	--self:ReleaseEvents()
	LxNodeBase.Dispose(self)
end

function BuildingAdCard:AutoInitLanguage(rootTrans)
	if CS.IsNullObject(rootTrans) then return end
	
	local spriteNode = nil 
	local spriteResName = nil
	local langResName = nil
	local spriteNodes = rootTrans:GetComponentsInChildren(typeSpriteRenderer, true)
	local nodeLen = spriteNodes.Length

	for k = 1, nodeLen do
		spriteNode = spriteNodes[k-1]
		if spriteNode and CS.IsValidObject(spriteNode.sprite) then
			spriteResName = spriteNode.sprite.name
			langResName,isNativeSize = gLGameLanguage:GetResName(spriteResName)
			if spriteResName ~= langResName then
				self:SetSpriteRenderer(spriteNode, langResName)
			end
		end 
	end
end

function BuildingAdCard:CreateAdCard(cityMap, trans)
	if CS.IsNullObject(trans) then return end

	self._cityMap = cityMap
	self._rootTrans = trans
	
	self:AutoInitLanguage(trans)

	self._adCardRoot = CS.FindTrans(self._rootTrans, "adCard")
	self._slotRoot = CS.FindTrans(self._rootTrans, "slotList")
	self._arrowoot = CS.FindTrans(self._rootTrans, "arrow")
	self._adeffroot = CS.FindTrans(self._rootTrans, "adeff")
	
	local adIconTrans1 = CS.FindTrans(self._adCardRoot, "icon1")
	local adIconTrans2 = CS.FindTrans(self._adCardRoot, "icon2")
	local adTextTrans1 = CS.FindTrans(self._adCardRoot, "text1")
	local adTextTrans2 = CS.FindTrans(self._adCardRoot, "text2")
	
	self._adIcon1 = adIconTrans1:GetComponent(typeSpriteRenderer)
	self._adIcon2 = adIconTrans2:GetComponent(typeSpriteRenderer)
	self._adText1 = adTextTrans1:GetComponent(typeSpriteRenderer)
	self._adText2 = adTextTrans2:GetComponent(typeSpriteRenderer)
	
	self._slotList = {}
	local slotNum = self._slotRoot.childCount
	local slotTrans = nil
	for i = 1,slotNum do
		slotTrans = CS.FindTrans(self._slotRoot, "slot"..i)
		if slotTrans then
			table.insert(self._slotList, slotTrans)
		end
	end
	
	self._arrow1 = CS.FindTrans(self._arrowoot, "arrow1")
	self._arrow2 = CS.FindTrans(self._arrowoot, "arrow2")
	
	self:_ShowEmpty()
	
	-- 初始化点击
	self._cityMap:SetBuildClick(self._arrow1, function()
		self:OnArrowClick(1)
		if self._autoChangetimer then
			self._autoChangetimer:Reset(self._autoChangeFunc, self._autoChangeSpaceTime, -1, true)
		end
	end)
	self._cityMap:SetBuildClick(self._arrow2, function()
		self:OnArrowClick(-1)
		if self._autoChangetimer then
			self._autoChangetimer:Reset(self._autoChangeFunc, self._autoChangeSpaceTime, -1, true)
		end
	end)
	self._cityMap:SetBuildClick(self._adCardRoot, function()
		self:OnAdCardClick()
	end)
end

