function BuildingAdCard:RefreshAdCard()
	self._adCardType = 0
	self._adCardList = {}
	--local adCardData = nil
	--local prePostList = gModelFunctionOpen:GetPrePostList()
	--if #prePostList > 0 then
	--	self._adCardType = 2
	--	adCardData = self:_InitPrePostData(prePostList)
	--else
	--	local noticeList = gModelGeneral:GetNoticeWndList()
	--	self._adCardType = 1
	--	adCardData = self:_InitNoticeData(noticeList)
	--end

	local dataList = gModelFunctionOpen:GetForeAdList()

	self._isEmpty = false
	local adCardData = self:GetCardDataList(dataList)
	-- local dataList = gModelActivity:GetActivityDataByModelId(ModelActivity.MODEL_ACTIVITY_TYPE_112)
	local dataList = {}
	if dataList[1] then
		local data = dataList[1]
		local sid = data.sid
		local moreInfo = JSON.decode(data.moreInfo)
		table.insert(adCardData,{icon = moreInfo.posterImg,sid = sid})
	end
	if not adCardData or 0 == #adCardData then
		self._isEmpty = true
		self:_ShowEmpty()
		return
	end
	
	if self._bLoginShow and self._adCardType == 1 then
		self._bLoginShow = true
		--GF.OpenWnd("WndPrePost")
	end
	
	self._adCardList = adCardData
	self:_ShowAdCardList(adCardData)
	
	if not self._autoChangetimer then
		if not self._autoChangeFunc then
			self._autoChangeFunc = function()
				self:OnArrowClick(1)
			end
		end
		self._autoChangetimer = LxTimer.LoopTimeCall(self._autoChangeFunc, self._autoChangeSpaceTime, true, -1)
	end 
end

function BuildingAdCard:ShowAdEffect()
	local dpEff = self._adEffect
	if dpEff then
		dpEff:SetVisible(true)
	else
		dpEff = LDisplayEffect:New()
		self._adEffect = dpEff
		local effName = "fx_zc3_touping"
		local trans = self._adeffroot
		if trans then
			dpEff:CreateEffect(trans, effName)
			dpEff:SetLoadedFunction(function()
				local dpTrans = dpEff:GetDisplayTrans()
				dpTrans.localPosition = Vector3.zero
				dpTrans.localScale = Vector3(1,1,1)
				dpTrans.name = effName
			end)
			dpEff:StartLoadEffect()
		end
	end
end

function BuildingAdCard:HidAdEffect()
	if self._adEffect then
		self._adEffect:SetVisible(false)
	end
end

