function BuildingAdCard:OnArrowClick(addIndex)
	local slotIndex = self._slotIndex + addIndex
	slotIndex = self:_ScrollSlotIndex(slotIndex)
	self:_SetAdIndex(slotIndex)
end

function BuildingAdCard:GetCardDataList(refList)
	local adList = {}
	for k,v in ipairs(refList) do
		table.insert(adList, {
			icon = v.poster,
		})
	end
	return adList
end

