function BuildingAdCard:_ShowEmpty()
	if CS.IsNullObject(self._adText1) then return end

	self:HidAdEffect()
	
	CS.ShowObject(self._adText1.transform, false)
	CS.ShowObject(self._adText2.transform, false)
	CS.ShowObject(self._arrow1, false)
	CS.ShowObject(self._arrow2, false)
	CS.ShowObject(self._slotRoot, false)
	
	self._curIconIndex = 0
	self._slotIndex = 0
	-- 设置空ad
	self:_SetAdIcon("mainui_txt_projection_1")
end

function BuildingAdCard:_ShowAdCardList(adList)
	local adCount = #adList
	if not adList or 0 == adCount then return end

	self:ShowAdEffect()
	
	if adCount > 1 then
		CS.ShowObject(self._arrow1, true)
		CS.ShowObject(self._arrow2, true)
	else
		CS.ShowObject(self._arrow1, false)
		CS.ShowObject(self._arrow2, false)
	end
	CS.ShowObject(self._adText1.transform, true)
	CS.ShowObject(self._adText2.transform, true)
	CS.ShowObject(self._slotRoot, true)
	
	self:_InitSlotUseList(adCount)
	local slotIndex = self:_ScrollSlotIndex(1)
	self:_SetAdIndex(slotIndex)
end

function BuildingAdCard:_InitSlotUseList(useNum)
	self._slotUseList = {}
	self._slotIndex = 0
	useNum = useNum or 0
	if useNum <= 0 then
		CS.ShowObject(self._slotRoot, false)
		CS.ShowObject(self._arrow1, false)
		CS.ShowObject(self._arrow2, false)
		return 
	end
	CS.ShowObject(self._slotRoot, true)
	if useNum > 1 then
		CS.ShowObject(self._arrow1, true)
		CS.ShowObject(self._arrow2, true)
	else
		CS.ShowObject(self._arrow1, false)
		CS.ShowObject(self._arrow2, false)
	end
	
	
	local slotNum = #self._slotList
	local slotTrans = nil
	for i = 1,slotNum do
		slotTrans = self._slotList[i]
		if i > useNum then
			CS.ShowObject(slotTrans, false)
		else
			CS.ShowObject(slotTrans, true)
			table.insert(self._slotUseList, slotTrans)
		end
	end
	
	if #self._slotUseList > 1 then
		local sortFunc = function (a,b)
			return a.position.x < b.position.x
		end
		table.sort(self._slotUseList, sortFunc)
	end
end

function BuildingAdCard:_ScrollSlotIndex(slotIndex)
	local slotMaxNum = #self._slotUseList
	if slotIndex < 1 then
		slotIndex = slotMaxNum
	elseif slotIndex > slotMaxNum then
		slotIndex = 1
	end
	
	local offKey = "mainui_line_light"
	local onKey = "mainui_line_dark"
	local slotTrans = nil
	for i = 1,slotMaxNum do
		slotTrans = self._slotUseList[i]
		if slotIndex == i then
			self:SetSpriteRenderer(slotTrans, onKey)
		else
			self:SetSpriteRenderer(slotTrans, offKey)
		end 
	end
	return slotIndex
end

function BuildingAdCard:_SetAdIndex(slotIndex)
	if self._slotIndex == slotIndex then return end

	self._slotIndex = slotIndex
	local adCardData = self._adCardList[slotIndex]
	if not adCardData then return end
	
	self:_SetAdIcon(adCardData.icon, adCardData.text)
end

function BuildingAdCard:_SetAdIcon(iconName, textName)
	if self._adIconSeqTween and self._adIconSeqTween:IsActive() then
		self._adIconSeqTween:Kill(true)
		self._adIconSeqTween = nil
	end
	
	if self._curIconIndex == 0 then
		self._curIconIndex = 1
		self:SetSpriteRenderer(self._adIcon1.transform, iconName)
		self:SetSpriteRenderer(self._adIcon2.transform, iconName)
	elseif self._curIconIndex == 1 then
		self._curIconIndex = 2
		self:SetSpriteRenderer(self._adIcon2.transform, iconName)
		
		self._adIcon1.color = Color.white
		self._adIcon2.color = Color.New(1,1,1,0)
		
		local alphaTween1 = CS.YXDOTweenModuleSprite.DOFade(self._adIcon1, 0, 0.3)
		local alphaTween2 = CS.YXDOTweenModuleSprite.DOFade(self._adIcon2, 1, 0.3)
		self._adIconSeqTween = Tweening.DOTween.Sequence()
		self._adIconSeqTween:SetAutoKill(true)
		self._adIconSeqTween:Join(alphaTween1)
		self._adIconSeqTween:Join(alphaTween2)

		local has = not string.isempty(textName)
		CS.ShowObject(self._adText1,has)
		CS.ShowObject(self._adText2,has)
		if has then
			self:SetSpriteRenderer(self._adText2.transform,textName)
			local alphaTween3 = CS.YXDOTweenModuleSprite.DOFade(self._adText1, 0, 0.3)
			local alphaTween4 = CS.YXDOTweenModuleSprite.DOFade(self._adText2, 1, 0.3)
			self._adIconSeqTween:Join(alphaTween3)
			self._adIconSeqTween:Join(alphaTween4)
		end
		
		self._adIconSeqTween:PlayForward()
		
	elseif self._curIconIndex == 2 then
		self._curIconIndex = 1
		self:SetSpriteRenderer(self._adIcon1.transform, iconName)
		
		self._adIcon1.color = Color.New(1,1,1,0)
		self._adIcon2.color = Color.white
		
		local alphaTween1 = CS.YXDOTweenModuleSprite.DOFade(self._adIcon1, 1, 0.3)
		local alphaTween2 = CS.YXDOTweenModuleSprite.DOFade(self._adIcon2, 0, 0.3)
		self._adIconSeqTween = Tweening.DOTween.Sequence()
		self._adIconSeqTween:SetAutoKill(true)
		self._adIconSeqTween:Join(alphaTween1)
		self._adIconSeqTween:Join(alphaTween2)

		local has = not string.isempty(textName)
		CS.ShowObject(self._adText1,has)
		CS.ShowObject(self._adText2,has)

		if has then
			self:SetSpriteRenderer(self._adText1.transform, textName)
			local alphaTween3 = CS.YXDOTweenModuleSprite.DOFade(self._adText1, 1, 0.3)
			local alphaTween4 = CS.YXDOTweenModuleSprite.DOFade(self._adText2, 0, 0.3)
			self._adIconSeqTween:Join(alphaTween3)
			self._adIconSeqTween:Join(alphaTween4)
		end
		
		self._adIconSeqTween:PlayForward()
	end
end

function BuildingAdCard:OnApplicationPause(isPause)
	if isPause then
		if self._autoChangetimer then
			LxTimer.LoopTimeStop(self._autoChangetimer)
			self._autoChangetimer = nil
		end
	else
		self:RefreshAdCard()
	end
end

return BuildingAdCard